import { useState, useEffect } from "react";
import { useNavigate, useParams } from "react-router-dom";
import "./EmployeeForm.css";

function AddEmployee() {

  const navigate = useNavigate();
  const { id } = useParams();
  const isEditMode = Boolean(id);

  const [activeTab,setActiveTab] = useState("personal");

  const [employee,setEmployee] = useState({
    firstName:"",
    lastName:"",
    empId:"",
    gender:"",
    dob:"",
    maritalStatus:"",
    email:"",
    aadhar:"",
    pan:"",
    designation:"",
    department:"",
    salary:"",
    role:"",
    skills:[],
    tempSkill:"",
    customSkill:"",
    bankName:"",
    accountNumber:"",
    ifsc:"",
    qualification:"",
    university:"",
    passingYear:""
  });

  const skillOptions=[
    "C","C++","Java","Advanced Java","Python",
    "NodeJS","React","Angular","MongoDB"
  ];

  const [designations,setDesignations]=useState([]);

  /* ==============================
     LOAD DESIGNATIONS FROM BACKEND
  ============================== */
  useEffect(()=>{
    const loadDesignations = async () => {
      try{
        const token = localStorage.getItem("token");

        const res = await fetch(
          "http://localhost:8080/api/designations",
          { headers:{ Authorization:`Bearer ${token}` } }
        );

        const data = await res.json();
        setDesignations(data);

      }catch(err){
        console.error("Failed to load designations",err);
      }
    };

    loadDesignations();
  },[]);

  /* ==============================
     LOAD EMPLOYEE FOR EDIT
  ============================== */
  useEffect(()=>{
    if(!isEditMode) return;

    const load = async()=>{
      try{
        const token = localStorage.getItem("token");

        const res = await fetch(
          `http://localhost:8080/api/profile/${id}`,
          { headers:{ Authorization:`Bearer ${token}` } }
        );

        const data = await res.json();

        setEmployee(prev=>({
          ...prev,
          ...data,
          designation: data.designation
            ? data.designation.trim()
            : "",
          skills:data.skills ? data.skills.split(",") : []
        }));

      }catch(err){
        console.error(err);
      }
    };

    load();
  },[id,isEditMode]);

  /* INPUT */
  const handleChange=(e)=>{
    const {name,value}=e.target;

    if(name==="pan"){
      setEmployee({...employee,pan:value.toUpperCase()});
      return;
    }

    setEmployee({...employee,[name]:value});
  };

  /* SAVE */
  const handleSubmit = async(e)=>{
    e.preventDefault();

    try{
      const token = localStorage.getItem("token");

      const payload={
        ...employee,
        skills:employee.skills.join(",")
      };

      const url=isEditMode
        ? `http://localhost:8080/api/profile/${id}`
        : `http://localhost:8080/api/profile`;

      const method=isEditMode?"PUT":"POST";

      const res=await fetch(url,{
        method,
        headers:{
          "Content-Type":"application/json",
          Authorization:`Bearer ${token}`
        },
        body:JSON.stringify(payload)
      });

      if(!res.ok) throw new Error();

      alert(isEditMode?"Updated Successfully":"Employee Created");

      navigate("/admin-dashboard/employee-details",{replace:true});
      setTimeout(()=>window.location.reload(),100);

    }catch(err){
      console.error(err);
      alert("Save Failed");
    }
  };

  const Field=(label,el)=>(
    <div className="form-field">
      <label>{label}</label>
      {el}
    </div>
  );

  return (
    <div className="add-employee-page">

      <h2>{isEditMode?"Edit Employee":"Add Employee"}</h2>

      <div className="tabs">
        {["personal","employment","bank","education"].map(t=>(
          <button
            key={t}
            type="button"
            className={`tab ${activeTab===t?"active":""}`}
            onClick={()=>setActiveTab(t)}
          >
            {t.toUpperCase()}
          </button>
        ))}
      </div>

      <form className="employee-form" onSubmit={handleSubmit}>

{/* ================= EMPLOYMENT ================= */}
{activeTab==="employment" && (
<>
<h3>Employment Details</h3>
<div className="employee-grid">

{Field("Designation",
<select
  name="designation"
  value={employee.designation || ""}
  onChange={handleChange}
>
  <option value="">Select</option>

  {designations.map(d=>(
    <option key={d.id} value={d.title}>
      {d.title}
    </option>
  ))}

</select>
)}

{Field("Salary",
<input name="salary" value={employee.salary} onChange={handleChange}/>
)}

</div>
</>
)}

<button className="save-btn" type="submit">
{isEditMode?"Update Employee":"Save Employee"}
</button>

      </form>
    </div>
  );
}

export default AddEmployee;
